  const ytNext = document.querySelector(".ytp-next-button, a.ytp-next-button");
  const vimeoNext = document.querySelector("[data-action=\"next\"]");
  const target = ytNext || vimeoNext;
  if (target instanceof HTMLElement) target.click();
})();

(function() {
  const ytPrev = document.querySelector(".ytp-prev-button");
  const vimeoPrev = document.querySelector("[data-action=\"previous\"]");
  const target = ytPrev || vimeoPrev;
  if (target instanceof HTMLElement) target.click();
})();

